import itertools
import multiprocessing
import multiprocessing.pool

import pytest

from order3_debruijn_arithmetic import *

i_range = 16
sequence = ""


def multiply_states(x):
    return mul_states3(x[:3], x[3:]) == inverse_rho3(rho3(x[:3]) * rho3(x[3:]))


def add_states(x):
    return add_states3(x[:3], x[3:]) == inverse_rho3(rho3(x[:3]) + rho3(x[3:]))


@pytest.fixture
def pool():
    ex_pool = multiprocessing.pool.Pool()
    yield ex_pool
    ex_pool.close()


class TestSanity:
    def test_rho3(self):
        assert rho3((1, 2, 0)) == 18

    def test_inverse_rho3(self):
        assert inverse_rho3(23) == (1, 2, 2)

    def test_lambda3(self):
        assert lambda3((1, 2, 0)) == (2, 3, 1)
        assert lambda3((0, 2, 1)) == (2, 0, 1)
    
    def test_inverse_lambda3(self):
        assert inverse_lambda3(2, 3, 1) == (1, 2, 0)
        assert inverse_lambda3(2, 0, 1) == (0, 2, 1)
    
    def test_carry_down(self):
        assert carry_down(4, -12, -1) == (3, 0, 0)

    def test_addition(self):
        assert add_states3((1, 2, 0), (0, 2, 1)) == (0, 0, 3)

    def test_carry_up(self):
        assert carry_up(4, 33, -1) == (5, 12, 1)
    
    def test_multiplication(self):
        assert mul_states3((1, 2, 0), (0, 2, 1)) == (2, 5, 3)


class TestEdgeCases:
    def test_null_state(self):
        assert rho3((0, 0, 0)) == 0
        assert inverse_rho3(0) == (0, 0, 0)
    
    def test_rho3_terminal_states(self):
        assert rho3((3, 3, 3)) == 61
        assert rho3((3, 3, 0)) == 62
        assert rho3((3, 0, 0)) == 63

    def test_inverse_rho3_terminal_states(self):
        assert inverse_rho3(61) == (3, 3, 3)
        assert inverse_rho3(62) == (3, 3, 0)
        assert inverse_rho3(63) == (3, 0, 0)
    
    def test_lambda3_terminal_states(self):
        assert lambda3((3, 3, 3)) == (3, 11, 1)
        assert lambda3((3, 3, 0)) == (3, 12, -1)
        assert lambda3((3, 0, 0)) == (4, 0, -1)

    def test_inverse_lambda3_terminal_states(self):
        assert inverse_lambda3(3, 11, 1) == (3, 3, 3)
        assert inverse_lambda3(3, 12, -1) == (3, 3, 0)
        assert inverse_lambda3(4, 0, -1) == (3, 0, 0)


class TestAll:
    def test_rho3(self):
        for a, b, c in itertools.product(range(i_range), range(i_range), range(i_range)):
            index = rho3((a, b, c))
            assert tuple(int(i, 16) for i in sequence[index:index + 3]) == (a, b, c)

    def test_inverse_rho3(self):
        for i in range(i_range ** 3):
            assert tuple(int(i, 16) for i in sequence[i:i + 3]) == inverse_rho3(i)

    def test_addition(self, pool):
        results = pool.map(add_states, itertools.product(range(i_range), range(i_range), range(i_range), range(i_range), range(i_range), range(i_range)))
        assert all(results)

    def test_multiplication(self, pool):
        results = pool.map(multiply_states, itertools.product(range(i_range), range(i_range), range(i_range), range(i_range), range(i_range), range(i_range)))
        assert all(results)
